709	static inline struct ucl_msgpack_parser *
710	ucl_msgpack_get_parser_from_type (unsigned char t)
711	{
712		unsigned int i, shift, mask;
713	
714		for (i = 0; i < sizeof (parsers) / sizeof (parsers[0]); i ++) {
715			shift = CHAR_BIT - parsers[i].prefixlen;
716			mask = parsers[i].prefix >> shift;
717	
718			if (mask == (t >> shift)) {
719				return &parsers[i];
720			}
721		}
722	
723		return NULL;
724	}
