726	static inline struct ucl_stack *
727	ucl_msgpack_get_container (struct ucl_parser *parser,
728			struct ucl_msgpack_parser *obj_parser, uint64_t len)
729	{
730		struct ucl_stack *stack;
731	
732		assert (obj_parser != NULL);
733	
734		if (obj_parser->flags & MSGPACK_FLAG_CONTAINER) {
735			assert ((len & MSGPACK_CONTAINER_BIT) == 0);
736			/*
737			 * Insert new container to the stack
738			 */
739			if (parser->stack == NULL) {
740				parser->stack = calloc (1, sizeof (struct ucl_stack));
741	
742				if (parser->stack == NULL) {
743					ucl_create_err (&parser->err, "no memory");
744					return NULL;
745				}
746			}
747			else {
748				stack = calloc (1, sizeof (struct ucl_stack));
749	
750				if (stack == NULL) {
751					ucl_create_err (&parser->err, "no memory");
752					return NULL;
753				}
754	
755				stack->next = parser->stack;
756				parser->stack = stack;
757			}
758	
759			parser->stack->level = len | MSGPACK_CONTAINER_BIT;
760	
761		}
762		else {
763			/*
764			 * Get the current stack top
765			 */
766			if (parser->stack) {
767				return parser->stack;
768			}
769			else {
770				ucl_create_err (&parser->err, "bad top level object for msgpack");
771				return NULL;
772			}
773		}
774	
775		return parser->stack;
776	}
777	
778	static bool
779	ucl_msgpack_is_container_finished (struct ucl_stack *container)
780	{
781		uint64_t level;
782	
783		assert (container != NULL);
784	
785		if (container->level & MSGPACK_CONTAINER_BIT) {
786			level = container->level & ~MSGPACK_CONTAINER_BIT;
787	
788			if (level == 0) {
789				return true;
790			}
791		}
792	
793		return false;
794	}
795	
796	static bool
797	ucl_msgpack_insert_object (struct ucl_parser *parser,
798			const unsigned char *key,
799			size_t keylen, ucl_object_t *obj)
800	{
801		uint64_t level;
802		struct ucl_stack *container;
803	
804		container = parser->stack;
805		assert (container != NULL);
806		assert (container->level > 0);
807		assert (obj != NULL);
808		assert (container->obj != NULL);
809	
810		if (container->obj->type == UCL_ARRAY) {
811			ucl_array_append (container->obj, obj);
812		}
813		else if (container->obj->type == UCL_OBJECT) {
814			if (key == NULL || keylen == 0) {
815				ucl_create_err (&parser->err, "cannot insert object with no key");
816				return false;
817			}
818	
819			obj->key = key;
820			obj->keylen = keylen;
821	
822			if (!(parser->flags & UCL_PARSER_ZEROCOPY)) {
823				ucl_copy_key_trash (obj);
824			}
825	
826			ucl_parser_process_object_element (parser, obj);
827		}
828		else {
829			ucl_create_err (&parser->err, "bad container type");
830			return false;
831		}
832	
833		if (container->level & MSGPACK_CONTAINER_BIT) {
834			level = container->level & ~MSGPACK_CONTAINER_BIT;
835			container->level = (level - 1) | MSGPACK_CONTAINER_BIT;
836		}
837	
838		return true;
839	}
840	
841	static struct ucl_stack *
842	ucl_msgpack_get_next_container (struct ucl_parser *parser)
843	{
844		struct ucl_stack *cur = NULL;
845		uint64_t level;
846	
847		cur = parser->stack;
848	
849		if (cur == NULL) {
850			return NULL;
851		}
852	
853		if (cur->level & MSGPACK_CONTAINER_BIT) {
854			level = cur->level & ~MSGPACK_CONTAINER_BIT;
855	
856			if (level == 0) {
857				/* We need to switch to the previous container */
858				parser->stack = cur->next;
859				parser->cur_obj = cur->obj;
860				free (cur);
861	
862				return ucl_msgpack_get_next_container (parser);
863			}
864		}
865	
866		/*
867		 * For UCL containers we don't know length, so we just insert the whole
868		 * message pack blob into the top level container
869		 */
870	
871		assert (cur->obj != NULL);
872	
873		return cur;
874	}
875	
876	#define CONSUME_RET do {									\
877		if (ret != -1) {										\
878			p += ret;											\
879			remain -= ret;										\
880			obj_parser = NULL;									\
881			assert (remain >= 0);								\
882		}														\
883		else {													\
884			ucl_create_err (&parser->err,						\
885				"cannot parse type %d of len %u",				\
886				(int)obj_parser->fmt,							\
887				(unsigned)len);									\
888			return false;										\
889		}														\
890	} while(0)
891	
892	#define GET_NEXT_STATE do {									\
893		container = ucl_msgpack_get_next_container (parser);	\
894		if (container == NULL) {								\
895			ucl_create_err (&parser->err,						\
896						"empty container");						\
897			return false;										\
898		}														\
899		next_state = container->obj->type == UCL_OBJECT ? 		\
900						read_assoc_key : read_array_value;		\
901	} while(0)
902	
903	static bool
904	ucl_msgpack_consume (struct ucl_parser *parser)
905	{
906		const unsigned char *p, *end, *key = NULL;
907		struct ucl_stack *container;
908		enum {
909			read_type,
910			start_assoc,
911			start_array,
912			read_assoc_key,
913			read_assoc_value,
914			finish_assoc_value,
915			read_array_value,
916			finish_array_value,
917			error_state
918		} state = read_type, next_state = error_state;
919		struct ucl_msgpack_parser *obj_parser;
920		uint64_t len;
921		ssize_t ret, remain, keylen = 0;
922	
923		p = parser->chunks->begin;
924		remain = parser->chunks->remain;
925		end = p + remain;
926	
927	
928		while (p < end) {
929			switch (state) {
930			case read_type:
931				obj_parser = ucl_msgpack_get_parser_from_type (*p);
932	
933				if (obj_parser == NULL) {
934					ucl_create_err (&parser->err, "unknown msgpack format: %x",
935							(unsigned int)*p);
936	
937					return false;
938				}
939				/* Now check length sanity */
940				if (obj_parser->flags & MSGPACK_FLAG_FIXED) {
941					if (obj_parser->len == 0) {
942						/* We have an embedded size */
943						len = *p & ~obj_parser->prefix;
944					}
945					else {
946						if (remain < obj_parser->len) {
947							ucl_create_err (&parser->err, "not enough data remain to "
948									"read object's length: %u remain, %u needed",
949									(unsigned)remain, obj_parser->len);
950	
951							return false;
952						}
953	
954						len = obj_parser->len;
955					}
956	
957					if (!(obj_parser->flags & MSGPACK_FLAG_TYPEVALUE)) {
958						/* We must pass value as the second byte */
959						if (remain > 0) {
960							p ++;
961							remain --;
962						}
963					}
964					else {
965						/* Len is irrelevant now */
966						len = 0;
967					}
968				}
969				else {
970					/* Length is not embedded */
971					if (remain < obj_parser->len) {
972						ucl_create_err (&parser->err, "not enough data remain to "
973								"read object's length: %u remain, %u needed",
974								(unsigned)remain, obj_parser->len);
975	
976						return false;
977					}
978	
979					p ++;
980					remain --;
981	
982					switch (obj_parser->len) {
983					case 1:
984						len = *p;
985						break;
986					case 2:
987						len = FROM_BE16 (*(uint16_t *)p);
988						break;
989					case 4:
990						len = FROM_BE32 (*(uint32_t *)p);
991						break;
992					case 8:
993						len = FROM_BE64 (*(uint64_t *)p);
994						break;
995					default:
996						assert (0);
997						break;
998					}
999	
1000					p += obj_parser->len;
1001					remain -= obj_parser->len;
1002				}
1003	
1004				if (obj_parser->flags & MSGPACK_FLAG_ASSOC) {
1005					/* We have just read the new associative map */
1006					state = start_assoc;
1007				}
1008				else if (obj_parser->flags & MSGPACK_FLAG_CONTAINER){
1009					state = start_array;
1010				}
1011				else {
1012					state = next_state;
1013				}
1014	
1015				break;
1016			case start_assoc:
1017				parser->cur_obj = ucl_object_new_full (UCL_OBJECT,
1018						parser->chunks->priority);
1019				/* Insert to the previous level container */
1020				if (parser->stack && !ucl_msgpack_insert_object (parser,
1021						key, keylen, parser->cur_obj)) {
1022					return false;
1023				}
1024				/* Get new container */
1025				container = ucl_msgpack_get_container (parser, obj_parser, len);
1026	
1027				if (container == NULL) {
1028					return false;
1029				}
1030	
1031				ret = obj_parser->func (parser, container, len, obj_parser->fmt,
1032						p, remain);
1033				CONSUME_RET;
1034				key = NULL;
1035				keylen = 0;
1036	
1037				if (len > 0) {
1038					state = read_type;
1039					next_state = read_assoc_key;
1040				}
1041				else {
1042					/* Empty object */
1043					state = finish_assoc_value;
1044				}
1045				break;
1046	
1047			case start_array:
1048				parser->cur_obj = ucl_object_new_full (UCL_ARRAY,
1049						parser->chunks->priority);
1050				/* Insert to the previous level container */
1051				if (parser->stack && !ucl_msgpack_insert_object (parser,
1052						key, keylen, parser->cur_obj)) {
1053					return false;
1054				}
1055				/* Get new container */
1056				container = ucl_msgpack_get_container (parser, obj_parser, len);
1057	
1058				if (container == NULL) {
1059					return false;
1060				}
1061	
1062				ret = obj_parser->func (parser, container, len, obj_parser->fmt,
1063									p, remain);
1064				CONSUME_RET;
1065	
1066				if (len > 0) {
1067					state = read_type;
1068					next_state = read_array_value;
1069				}
1070				else {
1071					/* Empty array */
1072					state = finish_array_value;
1073				}
1074				break;
1075	
1076			case read_array_value:
1077				/*
1078				 * p is now at the value start, len now contains length read and
1079				 * obj_parser contains the corresponding specific parser
1080				 */
1081				container = parser->stack;
1082	
1083				if (container == NULL) {
1084					return false;
1085				}
1086	
1087				ret = obj_parser->func (parser, container, len, obj_parser->fmt,
1088						p, remain);
1089				CONSUME_RET;
1090	
1091	
1092				/* Insert value to the container and check if we have finished array */
1093				if (!ucl_msgpack_insert_object (parser, NULL, 0,
1094						parser->cur_obj)) {
1095					return false;
1096				}
1097	
1098				if (ucl_msgpack_is_container_finished (container)) {
1099					state = finish_array_value;
1100				}
1101				else {
1102					/* Read more elements */
1103					state = read_type;
1104					next_state = read_array_value;
1105				}
1106	
1107				break;
1108	
1109			case read_assoc_key:
1110				/*
1111				 * Keys must have string type for ucl msgpack
1112				 */
1113				if (!(obj_parser->flags & MSGPACK_FLAG_KEY)) {
1114					ucl_create_err (&parser->err, "bad type for key: %u, expected "
1115							"string", (unsigned)obj_parser->fmt);
1116	
1117					return false;
1118				}
1119	
1120				key = p;
1121				keylen = len;
1122	
1123				if (keylen > remain || keylen == 0) {
1124					ucl_create_err (&parser->err, "too long or empty key");
1125					return false;
1126				}
1127	
1128				p += len;
1129				remain -= len;
1130	
1131				state = read_type;
1132				next_state = read_assoc_value;
1133				break;
1134	
1135			case read_assoc_value:
1136				/*
1137				 * p is now at the value start, len now contains length read and
1138				 * obj_parser contains the corresponding specific parser
1139				 */
1140				container = parser->stack;
1141	
1142				if (container == NULL) {
1143					return false;
1144				}
1145	
1146				ret = obj_parser->func (parser, container, len, obj_parser->fmt,
1147						p, remain);
1148				CONSUME_RET;
1149	
1150				assert (key != NULL && keylen > 0);
1151	
1152				if (!ucl_msgpack_insert_object (parser, key, keylen,
1153						parser->cur_obj)) {
1154					return false;
1155				}
1156	
1157				key = NULL;
1158				keylen = 0;
1159	
1160				if (ucl_msgpack_is_container_finished (container)) {
1161					state = finish_assoc_value;
1162				}
1163				else {
1164					/* Read more elements */
1165					state = read_type;
1166					next_state = read_assoc_key;
1167				}
1168				break;
1169	
1170			case finish_array_value:
1171			case finish_assoc_value:
1172				GET_NEXT_STATE;
1173				state = read_type;
1174				break;
1175	
1176			case error_state:
1177				ucl_create_err (&parser->err, "invalid state machine state");
1178	
1179				return false;
1180			}
1181		}
1182	
1183		/* Check the finishing state */
1184		switch (state) {
1185		case start_array:
1186		case start_assoc:
1187			/* Empty container at the end */
1188			if (len != 0) {
1189				ucl_create_err (&parser->err, "invalid non-empty container at the end");
1190	
1191				return false;
1192			}
1193	
1194			parser->cur_obj = ucl_object_new_full (
1195					state == start_array ? UCL_ARRAY : UCL_OBJECT,
1196					parser->chunks->priority);
1197			/* Insert to the previous level container */
1198			if (!ucl_msgpack_insert_object (parser,
1199					key, keylen, parser->cur_obj)) {
1200				return false;
1201			}
1202			/* Get new container */
1203			container = ucl_msgpack_get_container (parser, obj_parser, len);
1204	
1205			if (container == NULL) {
1206				return false;
1207			}
1208	
1209			ret = obj_parser->func (parser, container, len, obj_parser->fmt,
1210					p, remain);
1211			break;
1212	
1213		case read_array_value:
1214		case read_assoc_value:
1215			if (len != 0) {
1216				ucl_create_err (&parser->err, "unfinished value at the end");
1217	
1218				return false;
1219			}
1220	
1221			container = parser->stack;
1222	
1223			if (container == NULL) {
1224				return false;
1225			}
1226	
1227			ret = obj_parser->func (parser, container, len, obj_parser->fmt,
1228					p, remain);
1229			CONSUME_RET;
1230	
1231	
1232			/* Insert value to the container and check if we have finished array */
1233			if (!ucl_msgpack_insert_object (parser, NULL, 0,
1234					parser->cur_obj)) {
1235				return false;
1236			}
1237			break;
1238		case finish_array_value:
1239		case finish_assoc_value:
1240		case read_type:
1241			/* Valid finishing state */
1242			break;
1243		default:
1244			/* Invalid finishing state */
1245			ucl_create_err (&parser->err, "invalid state machine finishing state: %d",
1246					state);
1247	
1248			return false;
1249		}
1250	
1251		/* Rewind to the top level container */
1252		ucl_msgpack_get_next_container (parser);
1253		assert (parser->stack == NULL ||
1254				(parser->stack->level & MSGPACK_CONTAINER_BIT) == 0);
1255	
1256		return true;
1257	}
1258	
1259	bool
1260	ucl_parse_msgpack (struct ucl_parser *parser)
1261	{
1262		ucl_object_t *container = NULL;
1263		const unsigned char *p;
1264		bool ret;
1265	
1266		assert (parser != NULL);
1267		assert (parser->chunks != NULL);
1268		assert (parser->chunks->begin != NULL);
1269		assert (parser->chunks->remain != 0);
1270	
1271		p = parser->chunks->begin;
1272	
1273		if (parser->stack) {
1274			container = parser->stack->obj;
1275		}
1276	
1277		/*
1278		 * When we start parsing message pack chunk, we must ensure that we
1279		 * have either a valid container or the top object inside message pack is
1280		 * of container type
1281		 */
1282		if (container == NULL) {
1283			if ((*p & 0x80) != 0x80 && !(*p >= 0xdc && *p <= 0xdf)) {
1284				ucl_create_err (&parser->err, "bad top level object for msgpack");
1285				return false;
1286			}
1287		}
1288	
1289		ret = ucl_msgpack_consume (parser);
1290	
1291		if (ret && parser->top_obj == NULL) {
1292			parser->top_obj = parser->cur_obj;
1293		}
1294	
1295		return ret;
1296	}
