1318	static ssize_t
1319	ucl_msgpack_parse_string (struct ucl_parser *parser,
1320			struct ucl_stack *container, size_t len, enum ucl_msgpack_format fmt,
1321			const unsigned char *pos, size_t remain)
1322	{
1323		ucl_object_t *obj;
1324	
1325		if (len > remain) {
1326			return -1;
1327		}
1328	
1329		obj = ucl_object_new_full (UCL_STRING, parser->chunks->priority);
1330		obj->value.sv = pos;
1331		obj->len = len;
1332	
1333		if (!(parser->flags & UCL_PARSER_ZEROCOPY)) {
1334			ucl_copy_value_trash (obj);
1335		}
1336	
1337		parser->cur_obj = obj;
1338	
1339		return len;
1340	}
