1342	static ssize_t
1343	ucl_msgpack_parse_int (struct ucl_parser *parser,
1344			struct ucl_stack *container, size_t len, enum ucl_msgpack_format fmt,
1345			const unsigned char *pos, size_t remain)
1346	{
1347		ucl_object_t *obj;
1348	
1349		if (len > remain) {
1350			return -1;
1351		}
1352	
1353		obj = ucl_object_new_full (UCL_INT, parser->chunks->priority);
1354	
1355		switch (fmt) {
1356		case msgpack_positive_fixint:
1357			obj->value.iv = (*pos & 0x7f);
1358			len = 1;
1359			break;
1360		case msgpack_negative_fixint:
1361			obj->value.iv = - (*pos & 0x1f);
1362			len = 1;
1363			break;
1364		case msgpack_uint8:
1365			obj->value.iv = (unsigned char)*pos;
1366			len = 1;
1367			break;
1368		case msgpack_int8:
1369			obj->value.iv = (signed char)*pos;
1370			len = 1;
1371			break;
1372		case msgpack_int16:
1373			obj->value.iv = FROM_BE16 (*(int16_t *)pos);
1374			len = 2;
1375			break;
1376		case msgpack_uint16:
1377			obj->value.iv = FROM_BE16 (*(uint16_t *)pos);
1378			len = 2;
1379			break;
1380		case msgpack_int32:
1381			obj->value.iv = FROM_BE32 (*(int32_t *)pos);
1382			len = 4;
1383			break;
1384		case msgpack_uint32:
1385			obj->value.iv = FROM_BE32 (*(uint32_t *)pos);
1386			len = 4;
1387			break;
1388		case msgpack_int64:
1389			obj->value.iv = FROM_BE64 (*(int64_t *)pos);
1390			len = 8;
1391			break;
1392		case msgpack_uint64:
1393			obj->value.iv = FROM_BE64 (*(uint64_t *)pos);
1394			len = 8;
1395			break;
1396		default:
1397			assert (0);
1398			break;
1399		}
1400	
1401		parser->cur_obj = obj;
1402	
1403		return len;
1404	}
1405	
1406	static ssize_t
1407	ucl_msgpack_parse_float (struct ucl_parser *parser,
1408			struct ucl_stack *container, size_t len, enum ucl_msgpack_format fmt,
1409			const unsigned char *pos, size_t remain)
1410	{
1411		ucl_object_t *obj;
1412		union {
1413			uint32_t i;
1414			float f;
1415		} d;
1416	
1417		if (len > remain) {
1418			return -1;
1419		}
1420	
1421		obj = ucl_object_new_full (UCL_FLOAT, parser->chunks->priority);
1422	
1423		switch (fmt) {
1424		case msgpack_float32:
1425			d.i = FROM_BE32 (*(uint32_t *)pos);
1426			/* XXX: can be slow */
1427			obj->value.dv = d.f;
1428			len = 4;
1429			break;
1430		case msgpack_float64:
1431			obj->value.iv = FROM_BE64 (*(uint64_t *)pos);
1432			len = 8;
1433			break;
1434		default:
1435			assert (0);
1436			break;
1437		}
1438	
1439		parser->cur_obj = obj;
1440	
1441		return len;
1442	}
1443	
1444	static ssize_t
1445	ucl_msgpack_parse_bool (struct ucl_parser *parser,
1446			struct ucl_stack *container, size_t len, enum ucl_msgpack_format fmt,
1447			const unsigned char *pos, size_t remain)
1448	{
1449		ucl_object_t *obj;
1450	
1451		if (len > remain) {
1452			return -1;
1453		}
1454	
1455		obj = ucl_object_new_full (UCL_BOOLEAN, parser->chunks->priority);
1456	
1457		switch (fmt) {
1458		case msgpack_true:
1459			obj->value.iv = true;
1460			break;
1461		case msgpack_false:
1462			obj->value.iv = false;
1463			break;
1464		default:
1465			assert (0);
1466			break;
1467		}
1468	
1469		parser->cur_obj = obj;
1470	
1471		return 1;
1472	}
1473	
1474	static ssize_t
1475	ucl_msgpack_parse_null (struct ucl_parser *parser,
1476			struct ucl_stack *container, size_t len, enum ucl_msgpack_format fmt,
1477			const unsigned char *pos, size_t remain)
1478	{
1479		ucl_object_t *obj;
1480	
1481		if (len > remain) {
1482			return -1;
1483		}
1484	
1485		obj = ucl_object_new_full (UCL_NULL, parser->chunks->priority);
1486		parser->cur_obj = obj;
1487	
1488		return 1;
1489	}
1490	
1491	static ssize_t
1492	ucl_msgpack_parse_ignore (struct ucl_parser *parser,
1493			struct ucl_stack *container, size_t len, enum ucl_msgpack_format fmt,
1494			const unsigned char *pos, size_t remain)
1495	{
1496		if (len > remain) {
1497			return -1;
1498		}
1499	
1500		switch (fmt) {
1501		case msgpack_fixext1:
1502			len = 2;
1503			break;
1504		case msgpack_fixext2:
1505			len = 3;
1506			break;
1507		case msgpack_fixext4:
1508			len = 5;
1509			break;
1510		case msgpack_fixext8:
1511			len = 9;
1512			break;
1513		case msgpack_fixext16:
1514			len = 17;
1515			break;
1516		case msgpack_ext8:
1517		case msgpack_ext16:
1518		case msgpack_ext32:
1519			len = len + 1;
1520			break;
1521		default:
1522			ucl_create_err (&parser->err, "bad type: %x", (unsigned)fmt);
1523			return -1;
1524		}
1525	
1526		return len;
1527	}
