447		static void ucl_emit_ ## type ## _elt (struct ucl_emitter_context *ctx,	\
448			const ucl_object_t *obj, bool first, bool print_key) {	\
449			ucl_emitter_common_elt (ctx, obj, first, print_key, (compact));	\
450		}	\
