473	static void
474	ucl_emit_msgpack_elt (struct ucl_emitter_context *ctx,
475			const ucl_object_t *obj, bool first, bool print_key)
476	{
477		ucl_object_iter_t it;
478		struct ucl_object_userdata *ud;
479		const char *ud_out;
480		const ucl_object_t *cur, *celt;
481	
482		switch (obj->type) {
483		case UCL_INT:
484			ucl_emitter_print_key_msgpack (print_key, ctx, obj);
485			ucl_emitter_print_int_msgpack (ctx, ucl_object_toint (obj));
486			break;
487	
488		case UCL_FLOAT:
489		case UCL_TIME:
490			ucl_emitter_print_key_msgpack (print_key, ctx, obj);
491			ucl_emitter_print_double_msgpack (ctx, ucl_object_todouble (obj));
492			break;
493	
494		case UCL_BOOLEAN:
495			ucl_emitter_print_key_msgpack (print_key, ctx, obj);
496			ucl_emitter_print_bool_msgpack (ctx, ucl_object_toboolean (obj));
497			break;
498	
499		case UCL_STRING:
500			ucl_emitter_print_key_msgpack (print_key, ctx, obj);
501			ucl_emitter_print_string_msgpack (ctx, obj->value.sv, obj->len);
502			break;
503	
504		case UCL_NULL:
505			ucl_emitter_print_key_msgpack (print_key, ctx, obj);
506			ucl_emitter_print_null_msgpack (ctx);
507			break;
508	
509		case UCL_OBJECT:
510			ucl_emitter_print_key_msgpack (print_key, ctx, obj);
511			ucl_emit_msgpack_start_obj (ctx, obj, print_key);
512			it = ucl_object_iterate_new (obj);
513	
514			while ((cur = ucl_object_iterate_safe (it, true)) != NULL) {
515				LL_FOREACH (cur, celt) {
516					ucl_emit_msgpack_elt (ctx, celt, false, true);
517					/* XXX:
518					 * in msgpack the length of objects is encoded within a single elt
519					 * so in case of multi-value keys we are using merely the first
520					 * element ignoring others
521					 */
522				}
523			}
524	
525			ucl_object_iterate_free (it);
526			break;
527	
528		case UCL_ARRAY:
529			ucl_emitter_print_key_msgpack (print_key, ctx, obj);
530			ucl_emit_msgpack_start_array (ctx, obj, print_key);
531			it = ucl_object_iterate_new (obj);
532	
533			while ((cur = ucl_object_iterate_safe (it, true)) != NULL) {
534				ucl_emit_msgpack_elt (ctx, cur, false, false);
535			}
536	
537			ucl_object_iterate_free (it);
538			break;
539	
540		case UCL_USERDATA:
541			ud = (struct ucl_object_userdata *)obj;
542			ucl_emitter_print_key_msgpack (print_key, ctx, obj);
543	
544			if (ud->emitter) {
545				ud_out = ud->emitter (obj->value.ud);
546				if (ud_out == NULL) {
547					ud_out = "null";
548				}
549			}
550			ucl_emitter_print_string_msgpack (ctx, obj->value.sv, obj->len);
551			break;
552		}
553	}
