589	unsigned char *
590	ucl_object_emit_len (const ucl_object_t *obj, enum ucl_emitter emit_type,
591			size_t *outlen)
592	{
593		unsigned char *res = NULL;
594		struct ucl_emitter_functions *func;
595		UT_string *s;
596	
597		if (obj == NULL) {
598			return NULL;
599		}
600	
601		func = ucl_object_emit_memory_funcs ((void **)&res);
602		s = func->ud;
603	
604		if (func != NULL) {
605			ucl_object_emit_full (obj, emit_type, func);
606	
607			if (outlen != NULL) {
608				*outlen = s->i;
609			}
610	
611			ucl_object_emit_funcs_free (func);
612		}
613	
614		return res;
615	}
616	
617	bool
618	ucl_object_emit_full (const ucl_object_t *obj, enum ucl_emitter emit_type,
619			struct ucl_emitter_functions *emitter)
620	{
621		const struct ucl_emitter_context *ctx;
622		struct ucl_emitter_context my_ctx;
623		bool res = false;
624	
625		ctx = ucl_emit_get_standard_context (emit_type);
626		if (ctx != NULL) {
627			memcpy (&my_ctx, ctx, sizeof (my_ctx));
628			my_ctx.func = emitter;
629			my_ctx.indent = 0;
630			my_ctx.top = obj;
631	
632			my_ctx.ops->ucl_emitter_write_elt (&my_ctx, obj, true, false);
633			res = true;
634		}
635	
636		return res;
637	}
